{"content": "use std::sync::RwLock;
use crate::api::*;
use crate::distance::l2_distance;

const DIM: usize = 128;

pub struct VectorDB {
    // Flat storage for better cache locality
    // All vectors stored contiguously in a single buffer
    ids: RwLock<Vec<u64>>,
    vectors: RwLock<Vec<f32>>,
    count: RwLock<usize>,
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            ids: RwLock::new(Vec::new()),
            vectors: RwLock::new(Vec::new()),
            count: RwLock::new(0),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut ids = self.ids.write().unwrap();
        let mut vectors = self.vectors.write().unwrap();
        let mut count = self.count.write().unwrap();

        ids.push(id);
        vectors.extend(vector);
        *count += 1;
    }

    pub fn bulk_insert(&self, new_vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut ids = self.ids.write().unwrap();
        let mut vectors = self.vectors.write().unwrap();
        let mut count = self.count.write().unwrap();

        let mut new_ids = Vec::with_capacity(new_vectors.len());
        let mut new_data = Vec::with_capacity(new_vectors.len() * DIM);

        for (id, vec) in new_vectors {
            new_ids.push(id);
            new_data.extend(vec);
        }

        let inserted = new_ids.len();
        ids.append(&mut new_ids);
        vectors.extend(new_data);
        *count += inserted;

        inserted
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        let ids = self.ids.read().unwrap();
        let vectors = self.vectors.read().unwrap();
        let count = *self.count.read().unwrap();

        let k = top_k as usize;

        // Compute distances - access vectors in a cache-friendly manner
        // Process vectors in order, keeping them in L1/L2 cache as we go
        let mut distances: Vec<(u64, f64)> = Vec::with_capacity(count);

        for i in 0..count {
            let id = ids[i];
            let vec_start = i * DIM;
            let vec = &vectors[vec_start..vec_start + DIM];
            let dist = l2_distance(query, vec);
            distances.push((id, dist));
        }

        // Partial sort to get top_k smallest distances
        if k >= distances.len() {
            distances.sort_by(|a, b| a.1.partial_cmp(&b.1).unwrap());
        } else {
            // Use select_nth_unstable to find the k smallest elements
            let mid = distances.as_mut_slice().select_nth_unstable_by(k, |a, b| a.1.partial_cmp(&b.1).unwrap());
            // Sort only the first k elements
            mid.0.sort_by(|a, b| a.1.partial_cmp(&b.1).unwrap());
        }

        distances
            .into_iter()
            .take(k)
            .map(|(id, distance)| SearchResult { id, distance })
            .collect()
    }
}
