use rayon::prelude::*;
use crate::api::*;
use crate::distance::l2_distance;

const DIM: usize = 128;

pub struct VectorDB {
    // Flat storage for better cache locality
    ids: RwLock<Vec<u64>>,
    vectors: RwLock<Vec<f32>>,
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            ids: RwLock::new(Vec::new()),
            vectors: RwLock::new(Vec::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut ids = self.ids.write().unwrap();
        let mut vectors = self.vectors.write().unwrap();

        ids.push(id);
        vectors.extend(vector);
    }

    pub fn bulk_insert(&self, new_vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut ids = self.ids.write().unwrap();
        let mut vectors = self.vectors.write().unwrap();

        let mut new_ids = Vec::with_capacity(new_vectors.len());
        let mut new_data = Vec::with_capacity(new_vectors.len() * DIM);

        for (id, vec) in new_vectors {
            new_ids.push(id);
            new_data.extend(vec);
        }

        let inserted = new_ids.len();
        ids.append(&mut new_ids);
        vectors.extend(new_data);

        inserted
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        let ids = self.ids.read().unwrap();
        let vectors = self.vectors.read().unwrap();
        let count = ids.len();

        let k = top_k as usize;

        // Use a max-heap to track top-k efficiently
        // This avoids sorting all 1M distances
        use std::collections::BinaryHeap;
        use std::cmp::Reverse;

        // Build max-heap of (distance, id) - we want to keep smallest k distances
        // So we store Reverse(distance) for min-heap behavior, or use max-heap with Reverse
        let mut heap: BinaryHeap<(Reverse<f64>, u64)> = BinaryHeap::with_capacity(k + 1);

        for i in 0..count {
            let id = ids[i];
            let vec_start = i * DIM;
            let vec = &vectors[vec_start..vec_start + DIM];
            let dist = l2_distance(query, vec);

            if heap.len() < k {
                heap.push((Reverse(dist), id));
            } else if let Some(&(Reverse(max_dist), _)) = heap.peek() {
                if dist < max_dist {
                    heap.pop();
                    heap.push((Reverse(dist), id));
                }
            }
        }

        // Extract and sort results
        let mut results: Vec<SearchResult> = heap
            .into_iter()
            .map(|(Reverse(dist), id)| SearchResult { id, distance: dist })
            .collect();

        // Sort by distance ascending
        results.sort_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap());

        results
    }
}
